// =============================================================
// Aggregate decode quality test
// =============================================================

/// Decode all 9 WAV files and report aggregate statistics.
/// At minimum, we should decode messages from at least 7 of 9 files.
#[test]
fn test_decode_aggregate_quality() {
    let files = [
        "jtdx/000000_000001.wav",
        "jtdx/190227_155815.wav",
        "wsjt/210703_133430.wav",
        "wsjt/181201_180245.wav",
        "wsjt/170709_135615.wav",
        "basicft8/170923_082000.wav",
        "basicft8/170923_082015.wav",
        "basicft8/170923_082030.wav",
        "basicft8/170923_082045.wav",
    ];

    let mut total_messages = 0;
    let mut files_with_decodes = 0;

    for file in &files {
        let decoded = decode_wav_file(&fixture(file));
        let count = decoded.len();
        total_messages += count;
        if count > 0 {
            files_with_decodes += 1;
        }
        println!("{}: {} messages", file, count);
    }

    println!(
        "\nAggregate: {} messages from {}/{} files",
        total_messages,
        files_with_decodes,
        files.len()
    );

    assert!(
        files_with_decodes >= 7,
        "Should decode messages from at least 7 of 9 WAV files, got {}/9",
        files_with_decodes
    );

    assert!(
        total_messages >= 10,
        "Should decode at least 10 total messages across all files, got {}",
        total_messages
    );
}
